const t=JSON.parse('{"key":"v-052421f2","path":"/tech/java/Thread%E7%9A%84wait%E5%92%8Cnotify.html","title":"Thread的wait和notify","lang":"zh-CN","frontmatter":{"date":"2019-07-11T00:42:00.000Z","category":["Java"],"tag":["线程"],"description":"Thread的wait和notify 当不同线程之间需要通信时，就要使用到wait和notify这两个方法 wait的作用 让线程进入阻塞状态，并且会释放线程占有的锁，并交出CPU执行权限。 nofity 唤醒等待队列中的某个线程，如果时多个线程同时等待并不能指定唤醒某个线程，这有CPU来决定 notifyAll 这个方法则是唤醒等待队列中的所有线程 实践 实现一个容器，提供get和size两个方法，些两个线程，线程1添加10个元素到容器中，线程2实现监控元素的个数，当个数大于5时，线程2给出提示并结束","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/java/Thread%E7%9A%84wait%E5%92%8Cnotify.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"Thread的wait和notify"}],["meta",{"property":"og:description","content":"Thread的wait和notify 当不同线程之间需要通信时，就要使用到wait和notify这两个方法 wait的作用 让线程进入阻塞状态，并且会释放线程占有的锁，并交出CPU执行权限。 nofity 唤醒等待队列中的某个线程，如果时多个线程同时等待并不能指定唤醒某个线程，这有CPU来决定 notifyAll 这个方法则是唤醒等待队列中的所有线程 实践 实现一个容器，提供get和size两个方法，些两个线程，线程1添加10个元素到容器中，线程2实现监控元素的个数，当个数大于5时，线程2给出提示并结束"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-22T17:33:14.000Z"}],["meta",{"property":"article:tag","content":"线程"}],["meta",{"property":"article:published_time","content":"2019-07-11T00:42:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-22T17:33:14.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Thread的wait和notify\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2019-07-11T00:42:00.000Z\\",\\"dateModified\\":\\"2023-03-22T17:33:14.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"wait的作用","slug":"wait的作用","link":"#wait的作用","children":[]},{"level":2,"title":"nofity","slug":"nofity","link":"#nofity","children":[]},{"level":2,"title":"notifyAll","slug":"notifyall","link":"#notifyall","children":[]},{"level":2,"title":"代码","slug":"代码","link":"#代码","children":[]}],"git":{"createdTime":1679384580000,"updatedTime":1679506394000,"contributors":[{"name":"dhb","email":"xx158@qq.com","commits":1},{"name":"donghaibin","email":"xx158@qq.com","commits":1}]},"readingTime":{"minutes":1.63,"words":490},"filePathRelative":"tech/java/Thread的wait和notify.md","localizedDate":"2019年7月11日","excerpt":"<h1> Thread的wait和notify</h1>\\n<p>当不同线程之间需要通信时，就要使用到wait和notify这两个方法</p>\\n<h2> wait的作用</h2>\\n<p>让线程进入阻塞状态，并且会释放线程占有的锁，并交出CPU执行权限。</p>\\n<h2> nofity</h2>\\n<p>唤醒等待队列中的某个线程，如果时多个线程同时等待并不能指定唤醒某个线程，这有CPU来决定</p>\\n<h2> notifyAll</h2>\\n<p>这个方法则是唤醒等待队列中的所有线程</p>\\n<h1> 实践</h1>\\n<blockquote>\\n<p>实现一个容器，提供get和size两个方法，些两个线程，线程1添加10个元素到容器中，线程2实现监控元素的个数，当个数大于5时，线程2给出提示并结束</p>\\n</blockquote>","autoDesc":true}');export{t as data};
